const mongoose = require('mongoose');

// 1. Define the schema
const bookSchema = new mongoose.Schema({
  title:         { type: String,  required: true, trim: true },
  authorName:    { type: String,  required: true },
  publishedYear: { type: Number,  min: 1000, max: 2100 },
  price:         { type: Number,  required: true, min: 0 },
  genres:        [String],          // array of strings
  inStock:       { type: Boolean, default: true },
  rating:        { type: Number,  min: 0, max: 5 },
  createdAt:     { type: Date,    default: Date.now }
});

// 2. Create the model (collection name = 'books', pluralized)
const Book = mongoose.model('Book', bookSchema);

// 3. Use it
const book = new Book({ title: '1984', authorName: 'Orwell', price: 12.99 });
await book.save();

// Or shorthand:
await Book.create({ title: '1984', authorName: 'Orwell', price: 12.99 });

// Fluent query API
const books = await Book
  .find({ inStock: true })
  .where('price').lt(15)
  .select('title price')
  .sort('-publishedYear')
  .limit(10)
  .lean();  // .lean() returns plain JS objects, not Mongoose Documents (faster)

// Mongoose findById (shortcut for findOne({ _id: id }))
const book = await Book.findById('507f1f77bcf86cd799439011');

// findByIdAndUpdate — like findOneAndUpdate
const updated = await Book.findByIdAndUpdate(
  id,
  { $set: { price: 15.99 } },
  { new: true }  // return the updated document
);

// Virtuals — computed properties not stored in DB
bookSchema.virtual('priceWithTax').get(function() {
  return (this.price * 1.1).toFixed(2);
});

// Pre-save hook — run before every save()
bookSchema.pre('save', function(next) {
  this.title = this.title.trim();
  next();
});

// Post-save hook — run after save
bookSchema.post('save', function(doc) {
  console.log(`Saved: ${doc.title}`);
});

// ❌ WRONG — arrow function, 'this' is undefined or wrong
bookSchema.pre('save', async () => {
  this.title = this.title.trim();  // 'this' is NOT the document!
});

// ✅ CORRECT — regular function, 'this' is the document
bookSchema.pre('save', async function() {
  this.title = this.title.trim();  // 'this' IS the document being saved
});

// Same rule for virtuals:
// ❌ bookSchema.virtual('fullName').get(() => `${this.firstName} ${this.lastName}`);
// ✅ bookSchema.virtual('fullName').get(function() { return `${this.firstName} ${this.lastName}`; });

const bookSchema = new mongoose.Schema({
  title:  { type: String, required: true, trim: true, minLength: 1 },
  price:  { type: Number, required: true, min: 0 },
  rating: { type: Number, min: 0, max: 5 },
  status: { type: String, enum: ['draft', 'published', 'archived'] },
  // enum restricts value to one of the listed options
});

// Saving with invalid data throws ValidationError:
const b = new Book({ title: '', price: -5, status: 'unknown' });
await b.save();  // throws: title fails minLength, price fails min, status fails enum

const bookSchema = new mongoose.Schema({
  isbn: {
    type: String,
    validate: {
      validator: function(v) {
        return /^\d{13}$/.test(v);  // must be exactly 13 digits
      },
      message: props => `${props.value} is not a valid 13-digit ISBN`
    }
  }
});

// Without .lean() — returns Mongoose Document objects with full overhead
const books = await Book.find({ inStock: true });
// books[0].save() works, books[0].toObject() works, but slower

// With .lean() — returns plain JS objects, faster
const books = await Book.find({ inStock: true }).lean();
// books[0] is just { _id, title, price, ... } — no Mongoose methods
// Cannot call books[0].save() — use for display/read-only operations
